sql:
SELECT run_id, runtime, run_quality
FROM runs
WHERE runtime > (SELECT AVG(runtime) FROM runs);

SELECT config_name, COUNT(*) AS config_count
FROM run_history_configs
GROUP BY config_name;

SELECT config_name, description
FROM run_history_configs
WHERE run_history_config_id = 1;

external_knowledge:
- A valid run is a run with runtime greater than zero and run quality greater than 0.5; 
- A non-censored response is a response from a run that was not censored; 
- A successful run is considered to be a run with a non-censored response.

sql:
SELECT trial_id, COUNT(run_id) AS number_of_runs
FROM trial_runs
GROUP BY trial_id;

SELECT MAX(runtime) AS max_runtime
FROM runs
WHERE censored = 0 AND response_value > CEIL(ATANH(0.99));

SELECT run_type_name, description
FROM run_types
WHERE created_at > '2023-04-30 23:59:59';
